    35→
    36→#define REG_X_VAL_SCALE 256 // "fixed-point" precision for double -> int32_t conversion
    37→
    38→#define S2D_PIXEL_CONST 10
    39→#define S2D_CONST_OFFSET 0.375
    40→
    41→#define DEPTH_SENSOR_X_RES 1280
    42→#define DEPTH_MIRROR_X 0
    43→
    44→#define DEPTH_MAX_METRIC_VALUE FREENECT_DEPTH_MM_MAX_VALUE
    45→#define DEPTH_NO_MM_VALUE      FREENECT_DEPTH_MM_NO_VALUE
    46→#define DEPTH_MAX_RAW_VALUE    FREENECT_DEPTH_RAW_MAX_VALUE
    47→#define DEPTH_NO_RAW_VALUE     FREENECT_DEPTH_RAW_NO_VALUE
    48→
    49→#define DEPTH_X_OFFSET 1
    50→#define DEPTH_Y_OFFSET 1
    51→#define DEPTH_X_RES 640
    52→#define DEPTH_Y_RES 480
    53→
    54→// try to fill single empty pixels AKA "salt-and-pepper noise"
    55→// disabled by default, noise removal better handled in later stages
    56→// #define DENSE_REGISTRATION
    57→
    58→
    59→/// fill the table of horizontal shift values for metric depth -> RGB conversion
    60→static void freenect_init_depth_to_rgb(int32_t* depth_to_rgb, freenect_zero_plane_info* zpi)
    61→{
    62→	uint32_t i,x_scale = DEPTH_SENSOR_X_RES / DEPTH_X_RES;
    63→
    64→	double pixel_size = 1.0 / (zpi->reference_pixel_size * x_scale * S2D_PIXEL_CONST);
    65→	double pixels_between_rgb_and_ir_cmos = zpi->dcmos_rcmos_dist * pixel_size * S2D_PIXEL_CONST;
    66→	double reference_distance_in_pixels = zpi->reference_distance * pixel_size * S2D_PIXEL_CONST;
    67→
    68→	memset(depth_to_rgb, DEPTH_NO_MM_VALUE, DEPTH_MAX_METRIC_VALUE * sizeof(int32_t));
    69→
    70→	for (i = 0; i < DEPTH_MAX_METRIC_VALUE; i++) {
    71→		double current_depth_in_pixels = i * pixel_size;
    72→		depth_to_rgb[i] = (( pixels_between_rgb_and_ir_cmos * (current_depth_in_pixels - reference_distance_in_pixels) / current_depth_in_pixels) + S2D_CONST_OFFSET) * REG_X_VAL_SCALE;
    73→	}
    74→}
    75→
    76→// unrolled inner loop of the 11-bit unpacker
    77→static inline void unpack_8_pixels(uint8_t *raw, uint16_t *frame)
    78→{
    79→	uint16_t baseMask = 0x7FF;
    80→
    81→	uint8_t r0  = *(raw+0);
    82→	uint8_t r1  = *(raw+1);
    83→	uint8_t r2  = *(raw+2);
    84→	uint8_t r3  = *(raw+3);
    85→	uint8_t r4  = *(raw+4);
    86→	uint8_t r5  = *(raw+5);
    87→	uint8_t r6  = *(raw+6);
    88→	uint8_t r7  = *(raw+7);
    89→	uint8_t r8  = *(raw+8);
    90→	uint8_t r9  = *(raw+9);
    91→	uint8_t r10 = *(raw+10);
    92→
    93→	frame[0] =  (r0<<3)  | (r1>>5);
    94→	frame[1] = ((r1<<6)  | (r2>>2) )           & baseMask;
    95→	frame[2] = ((r2<<9)  | (r3<<1) | (r4>>7) ) & baseMask;
    96→	frame[3] = ((r4<<4)  | (r5>>4) )           & baseMask;
    97→	frame[4] = ((r5<<7)  | (r6>>1) )           & baseMask;
    98→	frame[5] = ((r6<<10) | (r7<<2) | (r8>>6) ) & baseMask;
    99→	frame[6] = ((r8<<5)  | (r9>>3) )           & baseMask;
   100→	frame[7] = ((r9<<8)  | (r10)   )           & baseMask;
   101→}
   102→
   103→// apply registration data to a single packed frame
   104→FN_INTERNAL int freenect_apply_registration(freenect_device* dev, uint8_t* input, uint16_t* output_mm, bool unpacked)
   105→{
   106→	freenect_registration* reg = &(dev->registration);
   107→	// set output buffer to zero using pointer-sized memory access (~ 30-40% faster than memset)
   108→	size_t i, *wipe = (size_t*)output_mm;
   109→	for (i = 0; i < DEPTH_X_RES * DEPTH_Y_RES * sizeof(uint16_t) / sizeof(size_t); i++) wipe[i] = DEPTH_NO_MM_VALUE;
   110→
   111→	uint16_t unpack[8];
   112→
   113→	uint32_t target_offset = DEPTH_Y_RES * reg->reg_pad_info.start_lines;
   114→	uint32_t x,y,source_index = 8;
   115→
   116→	for (y = 0; y < DEPTH_Y_RES; y++) {
   117→		for (x = 0; x < DEPTH_X_RES; x++) {
   118→
   119→                        uint16_t metric_depth;
   120→
   121→                        if (unpacked) {
   122→                                uint32_t buf_index = y * DEPTH_X_RES + x;
   123→                                metric_depth = reg->raw_to_mm_shift[((uint16_t *)input)[buf_index]];
   124→                        } else {
   125→                                // get 8 pixels from the packed frame
   126→                                if (source_index == 8) {
   127→                                        unpack_8_pixels( input, unpack );
   128→                                        source_index = 0;
   129→                                        input += 11;
   130→                                }
   131→
   132→                                // get the value at the current depth pixel, convert to millimeters
   133→                                metric_depth = reg->raw_to_mm_shift[ unpack[source_index++] ];
   134→                        }
   135→
   136→			// so long as the current pixel has a depth value
   137→			if (metric_depth == DEPTH_NO_MM_VALUE) continue;
   138→			if (metric_depth >= DEPTH_MAX_METRIC_VALUE) continue;
   139→
   140→			// calculate the new x and y location for that pixel
   141→			// using registration_table for the basic rectification
   142→			// and depth_to_rgb_shift for determining the x shift
   143→			uint32_t reg_index = DEPTH_MIRROR_X ? ((y + 1) * DEPTH_X_RES - x - 1) : (y * DEPTH_X_RES + x);
   144→			uint32_t nx = (reg->registration_table[reg_index][0] + reg->depth_to_rgb_shift[metric_depth]) / REG_X_VAL_SCALE;
   145→			uint32_t ny =  reg->registration_table[reg_index][1];
   146→
   147→			// ignore anything outside the image bounds
   148→			if (nx >= DEPTH_X_RES) continue;
   149→
   150→			// convert nx, ny to an index in the depth image array
   151→			uint32_t target_index = (DEPTH_MIRROR_X ? ((ny + 1) * DEPTH_X_RES - nx - 1) : (ny * DEPTH_X_RES + nx)) - target_offset;
   152→
   153→			// get the current value at the new location
   154→			uint16_t current_depth = output_mm[target_index];
   155→
   156→			// make sure the new location is empty, or the new value is closer
   157→			if ((current_depth == DEPTH_NO_MM_VALUE) || (current_depth > metric_depth)) {
   158→				output_mm[target_index] = metric_depth; // always save depth at current location
   159→
   160→				#ifdef DENSE_REGISTRATION
   161→					// if we're not on the first row, or the first column
   162→					if ((nx > 0) && (ny > 0)) {
   163→						output_mm[target_index - DEPTH_X_RES    ] = metric_depth; // save depth at (x,y-1)
   164→						output_mm[target_index - DEPTH_X_RES - 1] = metric_depth; // save depth at (x-1,y-1)
   165→						output_mm[target_index               - 1] = metric_depth; // save depth at (x-1,y)
   166→					} else if (ny > 0) {
   167→						output_mm[target_index - DEPTH_X_RES] = metric_depth; // save depth at (x,y-1)
   168→					} else if (nx > 0) {
   169→						output_mm[target_index - 1] = metric_depth; // save depth at (x-1,y)
   170→					}
   171→				#endif
   172→			}
   173→		}
   174→	}
   175→	return 0;
   176→}
   177→
   178→// Same as freenect_apply_registration, but don't bother aligning to the RGB image
   179→FN_INTERNAL int freenect_apply_depth_to_mm(freenect_device* dev, uint8_t* input_packed, uint16_t* output_mm)
   180→{
   181→	freenect_registration* reg = &(dev->registration);
   182→	uint16_t unpack[8];
   183→	uint32_t x,y,source_index = 8;
   184→	for (y = 0; y < DEPTH_Y_RES; y++) {
   185→		for (x = 0; x < DEPTH_X_RES; x++) {
   186→			// get 8 pixels from the packed frame
   187→			if (source_index == 8) {
   188→				unpack_8_pixels( input_packed, unpack );
   189→				source_index = 0;
   190→				input_packed += 11;
   191→			}
   192→			// get the value at the current depth pixel, convert to millimeters
   193→			uint16_t metric_depth = reg->raw_to_mm_shift[ unpack[source_index++] ];
   194→			output_mm[y * DEPTH_X_RES + x] = metric_depth < DEPTH_MAX_METRIC_VALUE ? metric_depth : DEPTH_MAX_METRIC_VALUE;
   195→		}
   196→	}
   197→	return 0;
   198→}
   199→
   200→// Same as freenect_apply_depth_to_mm, but don't need to unpack 11 bit depth values
   201→FN_INTERNAL int freenect_apply_depth_unpacked_to_mm(freenect_device* dev, uint16_t* input, uint16_t* output_mm)
   202→{
   203→	freenect_registration* reg = &(dev->registration);
   204→	uint32_t x,y;
   205→	for (y = 0; y < DEPTH_Y_RES; y++) {
   206→		for (x = 0; x < DEPTH_X_RES; x++) {
   207→			// get the value at the current depth pixel, convert to millimeters
   208→			uint32_t buf_index = y * DEPTH_X_RES + x;
   209→			uint16_t metric_depth = reg->raw_to_mm_shift[input[buf_index]];
   210→			output_mm[buf_index] = metric_depth < DEPTH_MAX_METRIC_VALUE ? metric_depth : DEPTH_MAX_METRIC_VALUE;
   211→		}
   212→	}
   213→	return 0;
   214→}
   215→
   216→// create temporary x/y shift tables
   217→static void freenect_create_dxdy_tables(double* reg_x_table, double* reg_y_table, int32_t resolution_x, int32_t resolution_y, freenect_reg_info* regdata )
   218→{
   219→
   220→	int64_t AX6 = regdata->ax;
   221→	int64_t BX6 = regdata->bx;
   222→	int64_t CX2 = regdata->cx;
   223→	int64_t DX2 = regdata->dx;
   224→
   225→	int64_t AY6 = regdata->ay;
   226→	int64_t BY6 = regdata->by;
   227→	int64_t CY2 = regdata->cy;
   228→	int64_t DY2 = regdata->dy;
   229→
   230→	// don't merge the shift operations - necessary for proper 32-bit clamping of extracted values
   231→	int64_t dX0 = (regdata->dx_start << 13) >> 4;
   232→	int64_t dY0 = (regdata->dy_start << 13) >> 4;
   233→
   234→	int64_t dXdX0 = (regdata->dxdx_start << 11) >> 3;
   235→	int64_t dXdY0 = (regdata->dxdy_start << 11) >> 3;
   236→	int64_t dYdX0 = (regdata->dydx_start << 11) >> 3;
   237→	int64_t dYdY0 = (regdata->dydy_start << 11) >> 3;
   238→
   239→	int64_t dXdXdX0 = (regdata->dxdxdx_start << 5) << 3;
   240→	int64_t dYdXdX0 = (regdata->dydxdx_start << 5) << 3;
   241→	int64_t dYdXdY0 = (regdata->dydxdy_start << 5) << 3;
   242→	int64_t dXdXdY0 = (regdata->dxdxdy_start << 5) << 3;
   243→	int64_t dYdYdX0 = (regdata->dydydx_start << 5) << 3;
   244→	int64_t dYdYdY0 = (regdata->dydydy_start << 5) << 3;
   245→
   246→	int32_t row,col,tOffs = 0;
   247→
   248→	for (row = 0 ; row < resolution_y ; row++) {
   249→
   250→		dXdXdX0 += CX2;
   251→
   252→		dXdX0   += dYdXdX0 >> 8;
   253→		dYdXdX0 += DX2;
   254→
   255→		dX0     += dYdX0 >> 6;
   256→		dYdX0   += dYdYdX0 >> 8;
   257→		dYdYdX0 += BX6;
   258→
   259→		dXdXdY0 += CY2;
   260→
   261→		dXdY0   += dYdXdY0 >> 8;
   262→		dYdXdY0 += DY2;
   263→
   264→		dY0     += dYdY0 >> 6;
   265→		dYdY0   += dYdYdY0 >> 8;
   266→		dYdYdY0 += BY6;
   267→
   268→		int64_t coldXdXdY0 = dXdXdY0, coldXdY0 = dXdY0, coldY0 = dY0;
   269→
   270→		int64_t coldXdXdX0 = dXdXdX0, coldXdX0 = dXdX0, coldX0 = dX0;
   271→
   272→		for (col = 0 ; col < resolution_x ; col++, tOffs++) {
   273→			reg_x_table[tOffs] = coldX0 * (1.0/(1<<17));
   274→			reg_y_table[tOffs] = coldY0 * (1.0/(1<<17));
   275→
   276→			coldX0     += coldXdX0 >> 6;
   277→			coldXdX0   += coldXdXdX0 >> 8;
   278→			coldXdXdX0 += AX6;
   279→
   280→			coldY0     += coldXdY0 >> 6;
   281→			coldXdY0   += coldXdXdY0 >> 8;
   282→			coldXdXdY0 += AY6;
   283→		}
   284→	}
   285→}
   286→
   287→static void freenect_init_registration_table(int32_t (*registration_table)[2], freenect_reg_info* reg_info) {
   288→
   289→	double* regtable_dx = (double*)malloc(DEPTH_X_RES*DEPTH_Y_RES*sizeof(double));
   290→	double* regtable_dy = (double*)malloc(DEPTH_X_RES*DEPTH_Y_RES*sizeof(double));
   291→	memset(regtable_dx, 0, DEPTH_X_RES*DEPTH_Y_RES * sizeof(double));
   292→	memset(regtable_dy, 0, DEPTH_X_RES*DEPTH_Y_RES * sizeof(double));
   293→	int32_t x,y,index = 0;
   294→
   295→	// create temporary dx/dy tables
   296→	freenect_create_dxdy_tables( regtable_dx, regtable_dy, DEPTH_X_RES, DEPTH_Y_RES, reg_info );
   297→
   298→	for (y = 0; y < DEPTH_Y_RES; y++) {
   299→		for (x = 0; x < DEPTH_X_RES; x++, index++) {
   300→			double new_x = x + regtable_dx[index] + DEPTH_X_OFFSET;
   301→			double new_y = y + regtable_dy[index] + DEPTH_Y_OFFSET;
   302→
   303→			if ((new_x < 0) || (new_y < 0) || (new_x >= DEPTH_X_RES) || (new_y >= DEPTH_Y_RES))
   304→				new_x = 2 * DEPTH_X_RES; // intentionally set value outside image bounds
   305→
   306→			registration_table[index][0] = new_x * REG_X_VAL_SCALE;
   307→			registration_table[index][1] = new_y;
   308→		}
   309→	}
   310→	free(regtable_dx);
   311→	free(regtable_dy);
   312→}
   313→
   314→// These are just constants.
   315→static double parameter_coefficient = 4;
   316→static double shift_scale = 10;
   317→static double pixel_size_factor = 1;
   318→
   319→/// convert raw shift value to metric depth (in mm)
   320→static uint16_t freenect_raw_to_mm(uint16_t raw, freenect_registration* reg)
   321→{
   322→	freenect_zero_plane_info* zpi = &(reg->zero_plane_info);
   323→	double fixed_ref_x = ((raw - (parameter_coefficient * reg->const_shift / pixel_size_factor)) / parameter_coefficient) - S2D_CONST_OFFSET;
   324→	double metric = fixed_ref_x * zpi->reference_pixel_size * pixel_size_factor;
   325→	return shift_scale * ((metric * zpi->reference_distance / (zpi->dcmos_emitter_dist - metric)) + zpi->reference_distance);
   326→}
   327→
   328→/// Compute registration tables.
   329→static void complete_tables(freenect_registration* reg) {
   330→	uint16_t i;
   331→	for (i = 0; i < DEPTH_MAX_RAW_VALUE; i++)
   332→		reg->raw_to_mm_shift[i] = freenect_raw_to_mm( i, reg);
   333→	reg->raw_to_mm_shift[DEPTH_NO_RAW_VALUE] = DEPTH_NO_MM_VALUE;
   334→
   335→	freenect_init_depth_to_rgb( reg->depth_to_rgb_shift, &(reg->zero_plane_info) );
   336→
   337→	freenect_init_registration_table( reg->registration_table, &(reg->reg_info) );
   338→}
   339→
   340→/// camera -> world coordinate helper function
   341→void freenect_camera_to_world(freenect_device* dev, int cx, int cy, int wz, double* wx, double* wy)
   342→{
   343→	double ref_pix_size = dev->registration.zero_plane_info.reference_pixel_size;
   344→	double ref_distance = dev->registration.zero_plane_info.reference_distance;
   345→	// We multiply cx and cy by these factors because they come from a 640x480 image,
   346→	// but the zero plane pixel size is for a 1280x1024 image.
   347→	// However, the 640x480 image is produced by cropping the 1280x1024 image
   348→	// to 1280x960 and then scaling by .5, so aspect ratio is maintained, and
   349→	// we should simply multiply by two in each dimension.
   350→	double factor = 2 * ref_pix_size * wz / ref_distance;
   351→	*wx = (double)(cx - DEPTH_X_RES/2) * factor;
   352→	*wy = (double)(cy - DEPTH_Y_RES/2) * factor;
   353→}
   354→
   355→/// RGB -> depth mapping function (inverse of default FREENECT_DEPTH_REGISTERED mapping)
   356→void freenect_map_rgb_to_depth(freenect_device* dev, uint16_t* depth_mm, uint8_t* rgb_raw, uint8_t* rgb_registered)
   357→{
   358→	uint32_t target_offset = dev->registration.reg_pad_info.start_lines * DEPTH_Y_RES;
   359→	int x,y;
   360→	int* map = (int*)malloc(DEPTH_Y_RES*DEPTH_X_RES* sizeof(int));
   361→	unsigned short* zBuffer = (unsigned short*)malloc(DEPTH_Y_RES*DEPTH_X_RES* sizeof(unsigned short));
   362→	memset(zBuffer, DEPTH_NO_MM_VALUE, DEPTH_X_RES*DEPTH_Y_RES * sizeof(unsigned short));
   363→
   364→	for (y = 0; y < DEPTH_Y_RES; y++) for (x = 0; x < DEPTH_X_RES; x++) {
   365→		uint32_t index = y * DEPTH_X_RES + x;
   366→		uint32_t cx,cy,cindex;
   367→
   368→		map[index] = -1;
   369→
   370→		int wz = depth_mm[index];
   371→
   372→		if (wz == DEPTH_NO_MM_VALUE) {
   373→			continue;
   374→		}
   375→
   376→		// coordinates in rgb image corresponding to x,y in depth image
   377→		cx = (dev->registration.registration_table[index][0] + dev->registration.depth_to_rgb_shift[wz]) / REG_X_VAL_SCALE;
   378→		cy =  dev->registration.registration_table[index][1] - target_offset;
   379→
   380→		if (cx >= DEPTH_X_RES) continue;
   381→
   382→		cindex = cy*DEPTH_X_RES+cx;
   383→		map[index] = cindex;
   384→
   385→		if (zBuffer[cindex] == DEPTH_NO_MM_VALUE || zBuffer[cindex] > wz) {
   386→			zBuffer[cindex] = wz;
   387→		}
   388→	}
   389→
   390→	for (y = 0; y < DEPTH_Y_RES; y++) for (x = 0; x < DEPTH_X_RES; x++) {
   391→		uint32_t index = y * DEPTH_X_RES + x;
   392→		uint32_t cindex = map[index];
   393→
   394→		// pixels without depth data or out of bounds are black
   395→		if (cindex == -1) {
   396→			index *= 3;
   397→			rgb_registered[index+0] = 0;
   398→			rgb_registered[index+1] = 0;
   399→			rgb_registered[index+2] = 0;
   400→
   401→			continue;
   402→		}
   403→
   404→		unsigned short currentDepth = depth_mm[index];
   405→		unsigned short minDepth = zBuffer[cindex];
   406→
   407→		// filters out pixels that are occluded
   408→		if (currentDepth <= minDepth) {
   409→			index *= 3;
   410→			cindex *= 3;
   411→
   412→			rgb_registered[index+0] = rgb_raw[cindex+0];
   413→			rgb_registered[index+1] = rgb_raw[cindex+1];
   414→			rgb_registered[index+2] = rgb_raw[cindex+2];
   415→		}
   416→	}
   417→
   418→	free(zBuffer);
   419→	free(map);
   420→}
   421→
   422→/// Allocate and fill registration tables
   423→/// This function should be called every time a new video (not depth!) mode is
   424→/// activated.
   425→FN_INTERNAL int freenect_init_registration(freenect_device* dev)
   426→{
   427→	freenect_registration* reg = &(dev->registration);
   428→
   429→	// Ensure that we free the previous tables before dropping the pointers, if there were any.
   430→	freenect_destroy_registration(&(dev->registration));
   431→
   432→	// Allocate tables.
   433→	reg->raw_to_mm_shift    = (uint16_t*)malloc( sizeof(uint16_t) * DEPTH_MAX_RAW_VALUE );
   434→	reg->depth_to_rgb_shift = (int32_t*)malloc( sizeof( int32_t) * DEPTH_MAX_METRIC_VALUE );
   435→	reg->registration_table = (int32_t (*)[2])malloc( sizeof( int32_t) * DEPTH_X_RES * DEPTH_Y_RES * 2 );
   436→
   437→	// Fill tables.
   438→	complete_tables(reg);
   439→
   440→	return 0;
   441→}
   442→
   443→freenect_registration freenect_copy_registration(freenect_device* dev)
   444→{
   445→	freenect_registration retval;
   446→	retval.reg_info = dev->registration.reg_info;
   447→	retval.reg_pad_info = dev->registration.reg_pad_info;
   448→	retval.zero_plane_info = dev->registration.zero_plane_info;
   449→	retval.const_shift = dev->registration.const_shift;
   450→	retval.raw_to_mm_shift    = (uint16_t*)malloc( sizeof(uint16_t) * DEPTH_MAX_RAW_VALUE );
   451→	retval.depth_to_rgb_shift = (int32_t*)malloc( sizeof( int32_t) * DEPTH_MAX_METRIC_VALUE );
   452→	retval.registration_table = (int32_t (*)[2])malloc( sizeof( int32_t) * DEPTH_X_RES * DEPTH_Y_RES * 2 );
   453→	complete_tables(&retval);
   454→	return retval;
   455→}
   456→
   457→int freenect_destroy_registration(freenect_registration* reg)
   458→{
   459→	if (reg->raw_to_mm_shift) {
   460→		free(reg->raw_to_mm_shift);
   461→		reg->raw_to_mm_shift = NULL;
   462→	}
   463→	if (reg->depth_to_rgb_shift) {
   464→		free(reg->depth_to_rgb_shift);
   465→		reg->depth_to_rgb_shift = NULL;
   466→	}
   467→	if (reg->registration_table) {
   468→		free(reg->registration_table);
